content.content:
  1→import { generateObject, type LanguageModel } from "ai";
  2→import { z } from "zod";
  3→import type { RecordId, Surreal } from "surrealdb";
  4→import type { ActionSpec, BudgetLimit, EvaluationResult } from "./types";
  5→import type { PolicyTraceEntry, IntentEvaluationContext } from "../policy/types";
  6→import { evaluatePolicyGate } from "../policy/policy-gate";
  7→import type { AlignmentResult, AlignmentCandidate } from "../objective/alignment";
  8→import { selectBestAlignment } from "../objective/alignment";
  9→
 10→// --- LLM Evaluator Port ---
 11→
 12→export type LlmEvaluator = (
 13→  intent: EvaluateIntentInput["intent"],
 14→  signal?: AbortSignal,
 15→) => Promise<EvaluationResult>;
 16→
 17→// --- Alignment Port ---
 18→
 19→/**
 20→ * Port: finds objective candidates matching an intent embedding.
 21→ * Implementation uses KNN two-step query pattern.
 22→ * Returns scored candidates for pure classification.
 23→ */
 24→export type FindAlignedObjectives = (
 25→  intentEmbedding: number[],
 26→  workspaceId: RecordId<"workspace">,
 27→) => Promise<AlignmentCandidate[]>;
 28→
 29→/**
 30→ * Port: creates a supports edge between intent and objective.
 31→ * Immutable once created.
 32→ */
 33→export type CreateSupportsEdge = (
 34→  intentId: RecordId<"intent">,
 35→  objectiveId: string,
 36→  alignmentScore: number,
 37→  alignmentMethod: "embedding" | "manual" | "rule",
 38→) => Promise<void>;
 39→
 40→// --- Pipeline Types ---
 41→
 42→type EvaluationOutput = EvaluationResult & {
 43→  policy_only: boolean;
 44→  policy_trace: PolicyTraceEntry[];
 45→  human_veto_required: boolean;
 46→  alignment?: AlignmentResult;
 47→};
 48→
 49→export type EvaluateIntentInput = {
 50→  intent: {
 51→    goal: string;
 52→    reasoning: string;
 53→    action_spec: ActionSpec;
 54→    budget_limit?: BudgetLimit;
 55→    priority?: number;
 56→  };
 57→  surreal: Surreal;
 58→  identityId: RecordId<"identity">;
 59→  workspaceId: RecordId<"workspace">;
 60→  requesterType: string;
 61→  requesterRole?: string;
 62→  llmEvaluator: LlmEvaluator;
 63→  timeoutMs?: number;
 64→  /** Optional: intent embedding for objective alignment (warning mode) */
 65→  intentEmbedding?: number[];
 66→  /** Optional: intent record ID for supports edge creation */
 67→  intentId?: RecordId<"intent">;
 68→  /** Optional: port to find aligned objectives via KNN */
 69→  findAlignedObjectives?: FindAlignedObjectives;
 70→  /** Optional: port to create supports edge */
 71→  createSupportsEdge?: CreateSupportsEdge;
 72→};
 73→
 74→const DEFAULT_EVAL_TIMEOUT_MS = 30_000;
 75→
 76→export async function evaluateIntent(
 77→  input: EvaluateIntentInput,
 78→): Promise<EvaluationOutput> {
 79→  const intentContext: IntentEvaluationContext = {
 80→    goal: input.intent.goal,
 81→    reasoning: input.intent.reasoning,
 82→    priority: input.intent.priority ?? 0,
 83→    action_spec: input.intent.action_spec,
 84→    budget_limit: input.intent.budget_limit,
 85→    requester_type: input.requesterType,
 86→    requester_role: input.requesterRole,
 87→  };
 88→
 89→  const gateResult = await evaluatePolicyGate(
 90→    input.surreal,
 91→    input.identityId,
 92→    input.workspaceId,
 93→    intentContext,
 94→  );
 95→
 96→  if (!gateResult.passed) {
 97→    return {
 98→      decision: "REJECT",
 99→      risk_score: 0,
100→      reason: gateResult.reason,
101→      policy_only: true,
102→      policy_trace: gateResult.policy_trace,
103→      human_veto_required: false,
104→    };
105→  }
106→
107→  const humanVetoRequired = gateResult.human_veto_required;
108→  const policyTrace = gateResult.policy_trace;
109→
110→  // --- Alignment step (warning mode: never blocks authorization) ---
111→  let alignmentResult: AlignmentResult | undefined;
112→  if (input.intentEmbedding && input.findAlignedObjectives) {
113→    try {
114→      const candidates = await input.findAlignedObjectives(
115→        input.intentEmbedding,
116→        input.workspaceId,
117→      );
118→      alignmentResult = selectBestAlignment(candidates);
119→
120→      // Create supports edge if matched and ports are available
121→      if (
122→        alignmentResult.classification === "matched" &&
123→        alignmentResult.objectiveId &&
124→        input.intentId &&
125→        input.createSupportsEdge
126→      ) {
127→        await input.createSupportsEdge(
128→          input.intentId,
129→          alignmentResult.objectiveId,
130→          alignmentResult.score,
131→          "embedding",
132→        );
133→      }
134→    } catch {
135→      // Alignment failure never blocks intent authorization (warning mode)
136→      alignmentResult = { classification: "none", score: 0 };
137→    }
138→  }
139→
140→  const timeoutMs = input.timeoutMs ?? DEFAULT_EVAL_TIMEOUT_MS;
141→  const controller = new AbortController();
142→  const timer = setTimeout(() => controller.abort(), timeoutMs);
143→
144→  try {
145→    const llmResult = await input.llmEvaluator(input.intent, controller.signal);
146→    return {
147→      ...llmResult,
148→      policy_only: false,
149→      policy_trace: policyTrace,
