  1→/**
  2→ * Objective & Behavior Acceptance Test Kit
  3→ *
  4→ * Extends acceptance-test-kit with helpers specific to the objective and
  5→ * behavior node feature set.
  6→ *
  7→ * All helpers use business language -- no technical jargon in function names.
  8→ *
  9→ * Driving ports:
 10→ *   POST /api/workspaces/:workspaceId/objectives       (objective CRUD)
 11→ *   GET  /api/workspaces/:workspaceId/objectives        (list objectives)
 12→ *   GET  /api/workspaces/:workspaceId/objectives/:id    (objective detail + progress)
 13→ *   POST /api/workspaces/:workspaceId/behaviors         (behavior record creation)
 14→ *   GET  /api/workspaces/:workspaceId/behaviors          (behavior listing)
 15→ *   POST /api/observe/scan/:workspaceId                 (coherence auditor via graph scan)
 16→ *   POST /api/workspaces/:workspaceId/learnings         (learning proposal)
 17→ *   SurrealDB direct queries                            (verification of outcomes)
 18→ */
 19→import { RecordId, type Surreal } from "surrealdb";
 20→import {
 21→  setupAcceptanceSuite,
 22→  createTestUser,
 23→  createTestUserWithMcp,
 24→  type AcceptanceTestRuntime,
 25→  type TestUser,
 26→  type TestUserWithMcp,
 27→} from "../acceptance-test-kit";
 28→
 29→// ---------------------------------------------------------------------------
 30→// Re-exports
 31→// ---------------------------------------------------------------------------
 32→
 33→export {
 34→  setupAcceptanceSuite,
 35→  createTestUser,
 36→  createTestUserWithMcp,
 37→  type AcceptanceTestRuntime,
 38→  type TestUser,
 39→  type TestUserWithMcp,
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Suite Setup
 44→// ---------------------------------------------------------------------------
 45→
 46→/**
 47→ * Sets up an objective-behavior acceptance test suite with isolated server + DB.
 48→ */
 49→export function setupObjectiveBehaviorSuite(
 50→  suiteName: string,
 51→): () => AcceptanceTestRuntime {
 52→  return setupAcceptanceSuite(suiteName);
 53→}
 54→
 55→// ---------------------------------------------------------------------------
 56→// Types
 57→// ---------------------------------------------------------------------------
 58→
 59→export type ObjectiveStatus = "draft" | "active" | "completed" | "archived" | "expired";
 60→export type ObjectivePriority = "low" | "medium" | "high" | "critical";
 61→
 62→export type SuccessCriterion = {
 63→  metric_name: string;
 64→  target_value: number;
 65→  current_value: number;
 66→  unit: string;
 67→};
 68→
 69→export type ObjectiveRecord = {
 70→  id: RecordId<"objective">;
 71→  title: string;
 72→  description?: string;
 73→  status: ObjectiveStatus;
 74→  priority: ObjectivePriority;
 75→  target_date?: string;
 76→  success_criteria: SuccessCriterion[];
 77→  workspace: RecordId<"workspace">;
 78→  embedding?: number[];
 79→  created_at: string;
 80→  updated_at?: string;
 81→};
 82→
 83→export type BehaviorRecord = {
 84→  id: RecordId<"behavior">;
 85→  metric_type: string;
 86→  score: number;
 87→  source_telemetry: Record<string, unknown>;
 88→  workspace: RecordId<"workspace">;
 89→  created_at: string;
 90→};
 91→
 92→export type SupportsEdge = {
 93→  id: RecordId<"supports">;
 94→  in: RecordId<"intent">;
 95→  out: RecordId<"objective">;
 96→  alignment_score: number;
 97→  alignment_method: "embedding" | "manual" | "rule";
 98→  reasoning?: string;
 99→};
100→
101→export type ExhibitsEdge = {
102→  id: RecordId<"exhibits">;
103→  in: RecordId<"identity">;
104→  out: RecordId<"behavior">;
105→};
106→
107→// ---------------------------------------------------------------------------
108→// Given Helpers -- Seed preconditions
109→// ---------------------------------------------------------------------------
110→
111→/**
112→ * Creates a workspace and test user for objective-behavior tests.
113→ */
114→export async function setupObjectiveWorkspace(
115→  baseUrl: string,
116→  surreal: Surreal,
117→  suffix: string,
118→): Promise<{
119→  user: TestUser;
120→  workspaceId: string;
121→  identityId: string;
122→}> {
123→  const workspaceId = `ws-${crypto.randomUUID()}`;
124→  const workspaceRecord = new RecordId("workspace", workspaceId);
125→
126→  const user = await createTestUser(baseUrl, suffix);
127→
128→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
129→    workspace: workspaceRecord,
130→    content: {
131→      name: `Objective Test Workspace ${suffix}`,
132→      status: "active",
133→      onboarding_complete: true,
134→      onboarding_turn_count: 0,
135→      onboarding_summary_pending: false,
136→      onboarding_started_at: new Date(),
137→      created_at: new Date(),
138→    },
139→  });
140→
141→  const identityId = `id-${crypto.randomUUID()}`;
142→  const identityRecord = new RecordId("identity", identityId);
143→
144→  await surreal.query(`CREATE $identity CONTENT $content;`, {
145→    identity: identityRecord,
146→    content: {
147→      name: `Test User ${suffix}`,
148→      type: "human",
149→      identity_status: "active",
150→      workspace: workspaceRecord,
151→      created_at: new Date(),
152→    },
153→  });
154→
155→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
156→    identity: identityRecord,
157→    workspace: workspaceRecord,
158→  });
159→
160→  return { user, workspaceId, identityId };
161→}
