163→/**
164→ * Creates an agent identity in the workspace.
165→ */
166→export async function createAgentIdentity(
167→  surreal: Surreal,
168→  workspaceId: string,
169→  agentName: string,
170→): Promise<{ identityId: string }> {
171→  const identityId = `id-${crypto.randomUUID()}`;
172→  const identityRecord = new RecordId("identity", identityId);
173→  const workspaceRecord = new RecordId("workspace", workspaceId);
174→
175→  await surreal.query(`CREATE $identity CONTENT $content;`, {
176→    identity: identityRecord,
177→    content: {
178→      name: agentName,
179→      type: "agent",
180→      identity_status: "active",
181→      workspace: workspaceRecord,
182→      created_at: new Date(),
183→    },
184→  });
185→
186→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
187→    identity: identityRecord,
188→    workspace: workspaceRecord,
189→  });
190→
191→  return { identityId };
192→}
193→
194→/**
195→ * Creates an objective node directly in the database.
196→ */
197→export async function createObjective(
198→  surreal: Surreal,
199→  workspaceId: string,
200→  opts: {
201→    title: string;
202→    description?: string;
203→    status?: ObjectiveStatus;
204→    priority?: ObjectivePriority;
205→    target_date?: string;
206→    success_criteria?: SuccessCriterion[];
207→    embedding?: number[];
208→  },
209→): Promise<{ objectiveId: string }> {
210→  const objectiveId = `obj-${crypto.randomUUID()}`;
211→  const objectiveRecord = new RecordId("objective", objectiveId);
212→  const workspaceRecord = new RecordId("workspace", workspaceId);
213→
214→  await surreal.query(`CREATE $objective CONTENT $content;`, {
215→    objective: objectiveRecord,
216→    content: {
217→      title: opts.title,
218→      description: opts.description ?? opts.title,
219→      status: opts.status ?? "active",
220→      priority: opts.priority ?? "high",
221→      target_date: opts.target_date,
222→      success_criteria: opts.success_criteria ?? [],
223→      workspace: workspaceRecord,
224→      embedding: opts.embedding,
225→      created_at: new Date(),
226→      updated_at: new Date(),
227→    },
228→  });
229→
230→  return { objectiveId };
231→}
