711→ */
712→export async function attemptBehaviorUpdate(
713→  surreal: Surreal,
714→  behaviorId: string,
715→  newScore: number,
716→): Promise<{ updated: boolean; error?: string }> {
717→  try {
718→    const behaviorRecord = new RecordId("behavior", behaviorId);
719→    await surreal.query(
720→      `UPDATE $behavior SET score = $score;`,
721→      { behavior: behaviorRecord, score: newScore },
