  workspaceId: string,
): Promise<Array<{ objectiveId: string; title: string; score: number }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `LET $candidates = SELECT id, title, workspace, status,
