210→    const scoringLogic = body.scoring_logic as string | undefined;
211→    const telemetryTypes = body.telemetry_types as string[] | undefined;
212→    const category = body.category as string | undefined;
213→    const createdById = body.created_by_id as string | undefined;
214→
215→    if (!title || title.trim().length === 0) return jsonError("title is required", 400);
216→    if (!goal || goal.trim().length === 0) return jsonError("goal is required", 400);
217→    if (!scoringLogic || scoringLogic.trim().length === 0) return jsonError("scoring_logic is required", 400);
218→    if (!telemetryTypes || !Array.isArray(telemetryTypes) || telemetryTypes.length === 0) return jsonError("telemetry_types must be a non-empty array", 400);
219→    if (!createdById || createdById.trim().length === 0) return jsonError("created_by_id is required", 400);
220→
221→    const input: CreateBehaviorDefinitionInput = {
222→      title: title.trim(),
223→      goal: goal.trim(),
224→      scoring_logic: scoringLogic.trim(),
225→      telemetry_types: telemetryTypes,
226→      ...(category !== undefined ? { category } : {}),
227→    };
228→
229→    const { definitionId } = await createBehaviorDefinition(
230→      deps.surreal,
231→      workspaceId,
232→      createdById,
233→      input,
234→    );
235→
236→    const record = await getBehaviorDefinition(deps.surreal, definitionId);
237→    if (!record) return jsonError("failed to retrieve created definition", 500);
238→
239→    return jsonResponse({ definition: serializeDefinition(record) }, 201);
240→  } catch (error) {
241→    logError("behavior.definition.create.failed", "Failed to create behavior definition", error, { workspaceId });
242→    return jsonError("failed to create behavior definition", 500);
243→  }
244→}
