294→async function handleUpdateDefinition(
295→  deps: ServerDependencies,
296→  _workspaceId: string,
297→  definitionId: string,
298→  request: Request,
299→): Promise<Response> {
300→  try {
301→    let body: Record<string, unknown>;
302→    try {
303→      body = (await request.json()) as Record<string, unknown>;
304→    } catch {
305→      return jsonError("Request body must be valid JSON", 400);
306→    }
307→
308→    const input: UpdateBehaviorDefinitionInput = {};
309→    if (body.goal !== undefined) input.goal = body.goal as string;
310→    if (body.scoring_logic !== undefined) input.scoring_logic = body.scoring_logic as string;
311→    if (body.telemetry_types !== undefined) input.telemetry_types = body.telemetry_types as string[];
312→    if (body.category !== undefined) input.category = body.category as string;
313→    if (body.status !== undefined) input.status = body.status as "draft" | "active" | "archived";
314→    if (body.enforcement_mode !== undefined) input.enforcement_mode = body.enforcement_mode as "warn_only" | "automatic";
315→    if (body.enforcement_threshold !== undefined) input.enforcement_threshold = body.enforcement_threshold as number;
316→
317→    const updated = await updateBehaviorDefinition(deps.surreal, definitionId, input);
318→    return jsonResponse({ definition: serializeDefinition(updated) }, 200);
319→  } catch (error) {
320→    const message = error instanceof Error ? error.message : "unknown error";
321→    if (message.includes("not found")) return jsonError(message, 404);
322→    if (message.includes("Invalid status transition")) return jsonError(message, 422);
323→    logError("behavior.definition.update.failed", "Failed to update behavior definition", error, { definitionId });
324→    return jsonError("failed to update behavior definition", 500);
325→  }
326→}
