  1→/**
  2→ * Scorer Dispatcher -- Routes telemetry scoring to LLM scorer.
  3→ *
  4→ * For each matched definition, produces an independent score via LLM.
  5→ * Persists scored behavior records via createBehavior.
  6→ */
  7→
  8→import type { LanguageModel } from "ai";
  9→import type { Surreal } from "surrealdb";
 10→import type { BehaviorDefinitionRecord, LlmScorerResult } from "./definition-types";
 11→import { scoreTelemetryWithLlm } from "./llm-scorer";
 12→import { createBehavior, type BehaviorInput } from "./queries";
 13→import { logInfo } from "../http/observability";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Types
 17→// ---------------------------------------------------------------------------
 18→
 19→export type ScoringRequest = {
 20→  telemetryType: string;
 21→  telemetryPayload: Record<string, unknown>;
 22→  identityId: string;
 23→  workspaceId: string;
 24→  sessionId?: string;
 25→};
 26→
 27→export type ScoredResult = {
 28→  definitionId: string;
 29→  definitionTitle: string;
 30→  definitionVersion: number;
 31→  score: number;
 32→  rationale?: string;
 33→  evidenceChecked?: string[];
 34→  behaviorId: string;
 35→};
 36→
 37→export type DispatcherDependencies = {
 38→  surreal: Surreal;
 39→  scorerModel?: LanguageModel;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Score a single definition against telemetry
 44→// ---------------------------------------------------------------------------
 45→
 46→async function scoreOneDefinition(
 47→  definition: BehaviorDefinitionRecord,
 48→  request: ScoringRequest,
 49→  deps: DispatcherDependencies,
 50→): Promise<ScoredResult | undefined> {
 51→  const definitionId = definition.id.id as string;
 52→
 53→  if (!deps.scorerModel) {
 54→    logInfo("behavior.dispatcher", "LLM scorer model not configured, skipping scoring", {
 55→      definition_title: definition.title,
 56→    });
 57→    return undefined;
 58→  }
 59→
 60→  const llmResult: LlmScorerResult | undefined = await scoreTelemetryWithLlm(
 61→    deps.scorerModel,
 62→    definition,
 63→    request.telemetryPayload,
 64→  );
 65→
 66→  if (!llmResult) {
 67→    logInfo("behavior.dispatcher", "LLM scorer returned no result (timeout or failure)", {
 68→      definition_title: definition.title,
 69→    });
 70→    return undefined;
 71→  }
 72→
 73→  const { behaviorId } = await persistScore(deps.surreal, request, {
 74→    definitionId,
 75→    definitionVersion: definition.version,
 76→    metricType: definition.title,
 77→    score: llmResult.score,
 78→    sourceTelemetry: {
 79→      rationale: llmResult.rationale,
 80→      evidence_checked: llmResult.evidence_checked,
 81→      definition_version: definition.version,
 82→      telemetry_type: request.telemetryType,
 83→    },
 84→  });
 85→
 86→  return {
 87→    definitionId,
 88→    definitionTitle: definition.title,
 89→    definitionVersion: definition.version,
 90→    score: llmResult.score,
 91→    rationale: llmResult.rationale,
 92→    evidenceChecked: llmResult.evidence_checked,
 93→    behaviorId,
 94→  };
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// Persist Score (IO boundary)
 99→// ---------------------------------------------------------------------------
100→
101→async function persistScore(
102→  surreal: Surreal,
103→  request: ScoringRequest,
104→  score: {
105→    definitionId: string;
106→    definitionVersion: number;
107→    metricType: string;
108→    score: number;
109→    sourceTelemetry: Record<string, unknown>;
110→  },
111→): Promise<{ behaviorId: string }> {
112→  const input: BehaviorInput = {
113→    metricType: score.metricType,
114→    score: score.score,
115→    sourceTelemetry: score.sourceTelemetry,
116→    workspaceId: request.workspaceId,
117→    sessionId: request.sessionId,
118→    definitionId: score.definitionId,
119→    definitionVersion: score.definitionVersion,
120→  };
121→
122→  return createBehavior(surreal, request.identityId, input);
123→}
124→
125→// ---------------------------------------------------------------------------
126→// Public API: Dispatch scoring for matched definitions
127→// ---------------------------------------------------------------------------
128→
129→/**
130→ * Scores telemetry against each matched definition independently via LLM.
131→ * Returns an array of scored results (one per definition that produced a score).
132→ * Definitions that fail scoring are omitted from results (no partial failures).
133→ */
134→export async function dispatchScoring(
135→  matchedDefinitions: readonly BehaviorDefinitionRecord[],
136→  request: ScoringRequest,
137→  deps: DispatcherDependencies,
138→): Promise<ScoredResult[]> {
139→  if (matchedDefinitions.length === 0) return [];
140→
141→  logInfo("behavior.dispatcher", "Dispatching scoring", {
142→    telemetry_type: request.telemetryType,
143→    matched_definitions: matchedDefinitions.length,
144→  });
145→
146→  const results: ScoredResult[] = [];
147→
148→  for (const definition of matchedDefinitions) {
149→    const result = await scoreOneDefinition(definition, request, deps);
150→    if (result) {
151→      results.push(result);
152→    }
153→  }
154→
155→  logInfo("behavior.dispatcher", "Scoring complete", {
156→    telemetry_type: request.telemetryType,
157→    scored: results.length,
158→    skipped: matchedDefinitions.length - results.length,
159→  });
160→
161→  return results;
162→}
