  1→/**
  2→ * Behavior CRUD Queries
  3→ *
  4→ * Driven port implementations for behavior record persistence.
  5→ * All queries use RecordId objects per project convention.
  6→ * Behavior records are append-only -- no UPDATE queries.
  7→ */
  8→import { RecordId, type Surreal } from "surrealdb";
  9→import type { IntentEvaluationContext } from "../policy/types";
 10→import type {
 11→  BehaviorDefinitionRecord,
 12→  CreateBehaviorDefinitionInput,
 13→  UpdateBehaviorDefinitionInput,
 14→  DefinitionStatus,
 15→} from "./definition-types";
 16→
 17→// ---------------------------------------------------------------------------
 18→// Types
 19→// ---------------------------------------------------------------------------
 20→
 21→export type BehaviorInput = {
 22→  metricType: string;
 23→  score: number;
 24→  sourceTelemetry: Record<string, unknown>;
 25→  workspaceId: string;
 26→  sessionId?: string;
 27→  definitionId?: string;
 28→  definitionVersion?: number;
 29→};
 30→
 31→export type BehaviorRow = {
 32→  id: RecordId<"behavior">;
 33→  metric_type: string;
 34→  score: number;
 35→  source_telemetry: Record<string, unknown>;
 36→  definition: RecordId<"behavior_definition">;
 37→  definition_version: number;
 38→  workspace: RecordId<"workspace">;
 39→  session?: RecordId<"agent_session">;
 40→  created_at: string;
 41→};
 42→
 43→export type ExhibitsEdgeRow = {
 44→  id: RecordId<"exhibits">;
 45→  in: RecordId<"identity">;
 46→  out: RecordId<"behavior">;
 47→  created_at: string;
 48→};
 49→
 50→// ---------------------------------------------------------------------------
 51→// Create Behavior Record (append-only)
 52→// ---------------------------------------------------------------------------
 53→
 54→/**
 55→ * Creates a behavior record and the exhibits edge linking identity to behavior.
 56→ * Append-only: never updates existing records.
 57→ */
 58→export async function createBehavior(
 59→  surreal: Surreal,
 60→  identityId: string,
 61→  input: BehaviorInput,
 62→): Promise<{ behaviorId: string }> {
 63→  const behaviorId = `beh-${crypto.randomUUID()}`;
 64→  const behaviorRecord = new RecordId("behavior", behaviorId);
 65→  const workspaceRecord = new RecordId("workspace", input.workspaceId);
 66→  const identityRecord = new RecordId("identity", identityId);
 67→
 68→  const content: Record<string, unknown> = {
 69→    metric_type: input.metricType,
 70→    score: input.score,
 71→    source_telemetry: input.sourceTelemetry,
 72→    workspace: workspaceRecord,
 73→    created_at: new Date(),
 74→  };
 75→
 76→  if (input.sessionId) {
 77→    content.session = new RecordId("agent_session", input.sessionId);
 78→  }
 79→
 80→  if (input.definitionId) {
 81→    content.definition = new RecordId("behavior_definition", input.definitionId);
 82→  }
 83→
 84→  if (input.definitionVersion !== undefined) {
 85→    content.definition_version = input.definitionVersion;
 86→  }
 87→
 88→  await surreal.query(`CREATE $behavior CONTENT $content;`, {
 89→    behavior: behaviorRecord,
 90→    content,
 91→  });
 92→
 93→  // Create exhibits edge: identity ->exhibits-> behavior
 94→  await surreal.query(
 95→    `RELATE $identity->exhibits->$behavior SET created_at = time::now();`,
 96→    { identity: identityRecord, behavior: behaviorRecord },
 97→  );
 98→
 99→  return { behaviorId };
100→}
101→
102→// ---------------------------------------------------------------------------
103→// Query Behavior Records
104→// ---------------------------------------------------------------------------
105→
106→/**
107→ * Lists behavior records for an identity, optionally filtered by metric type.
108→ * Returns records ordered by created_at DESC (most recent first).
109→ */
110→export async function listBehaviors(
111→  surreal: Surreal,
112→  identityId: string,
113→  metricType?: string,
114→): Promise<BehaviorRow[]> {
115→  const identityRecord = new RecordId("identity", identityId);
116→
117→  // Traverse exhibits edges from identity to behavior
118→  const edgeRows = (await surreal.query(
119→    `SELECT ->exhibits->behavior AS behaviors FROM $identity;`,
120→    { identity: identityRecord },
121→  )) as Array<Array<{ behaviors: RecordId[] }>>;
122→
123→  const behaviorIds = edgeRows[0]?.[0]?.behaviors ?? [];
124→  if (behaviorIds.length === 0) return [];
125→
126→  const query = metricType
127→    ? `SELECT * FROM behavior WHERE id IN $ids AND metric_type = $mt ORDER BY created_at DESC;`
128→    : `SELECT * FROM behavior WHERE id IN $ids ORDER BY created_at DESC;`;
129→  const rows = (await surreal.query(query, { ids: behaviorIds, mt: metricType })) as Array<BehaviorRow[]>;
130→  return rows[0] ?? [];
131→}
132→
133→/**
134→ * Gets the latest behavior score for an identity and metric type.
135→ */
136→export async function getLatestScore(
137→  surreal: Surreal,
138→  identityId: string,
139→  metricType: string,
140→): Promise<number | undefined> {
141→  const records = await listBehaviors(surreal, identityId, metricType);
142→  return records[0]?.score;
143→}
144→
145→/**
146→ * Gets the latest score per unique metric_type for an identity.
147→ * Returns a map of metric_type -> score, using the most recent record per metric.
148→ * Used for context enrichment before policy gate evaluation.
149→ */
150→export async function getLatestBehaviorScores(
151→  surreal: Surreal,
152→  identityId: string,
153→): Promise<Record<string, number>> {
154→  const allRecords = await listBehaviors(surreal, identityId);
155→
156→  // Records are already sorted by created_at DESC from listBehaviors.
157→  // Take the first (most recent) score per metric_type.
158→  const scores: Record<string, number> = {};
159→  for (const record of allRecords) {
160→    if (!(record.metric_type in scores)) {
161→      scores[record.metric_type] = record.score;
162→    }
163→  }
164→
165→  return scores;
166→}
167→
168→/**
169→ * Enriches an IntentEvaluationContext with behavior scores for an identity.
170→ * Context enrichment happens before policy gate evaluation, not inside it.
171→ * Returns a new context object (immutable -- does not mutate the input).
172→ */
173→export async function enrichBehaviorScores(
174→  surreal: Surreal,
175→  identityId: string,
176→  context: IntentEvaluationContext,
177→): Promise<IntentEvaluationContext> {
178→  const scores = await getLatestBehaviorScores(surreal, identityId);
179→  return { ...context, behavior_scores: scores };
180→}
181→
182→/**
183→ * Lists behavior records for a workspace, optionally filtered by metric type.
184→ */
185→export async function listWorkspaceBehaviors(
186→  surreal: Surreal,
187→  workspaceId: string,
188→  metricType?: string,
189→  limit = 50,
190→): Promise<BehaviorRow[]> {
191→  const workspaceRecord = new RecordId("workspace", workspaceId);
192→
193→  const query = metricType
194→    ? `SELECT * FROM behavior WHERE workspace = $ws AND metric_type = $mt ORDER BY created_at DESC LIMIT $limit;`
195→    : `SELECT * FROM behavior WHERE workspace = $ws ORDER BY created_at DESC LIMIT $limit;`;
196→  const rows = (await surreal.query(query, { ws: workspaceRecord, mt: metricType, limit })) as Array<BehaviorRow[]>;
197→  return rows[0] ?? [];
198→}
199→
200→// ---------------------------------------------------------------------------
201→// Status Transition Validation (pure function)
202→// ---------------------------------------------------------------------------
203→
204→const VALID_STATUS_TRANSITIONS: Record<DefinitionStatus, DefinitionStatus[]> = {
205→  draft: ["active", "archived"],
206→  active: ["archived"],
207→  archived: [],
208→};
209→
210→/**
211→ * Validates a status transition for a behavior definition.
212→ * Valid transitions: draft->active, draft->archived, active->archived.
213→ * Returns an error message if invalid, undefined if valid.
214→ */
215→export function validateStatusTransition(
216→  currentStatus: DefinitionStatus,
217→  newStatus: DefinitionStatus,
218→): string | undefined {
219→  if (currentStatus === newStatus) return undefined;
220→  const allowed = VALID_STATUS_TRANSITIONS[currentStatus];
221→  if (!allowed.includes(newStatus)) {
222→    return `Invalid status transition: ${currentStatus} -> ${newStatus}`;
223→  }
224→  return undefined;
225→}
226→
227→// ---------------------------------------------------------------------------
228→// Behavior Definition CRUD
229→// ---------------------------------------------------------------------------
230→
231→/**
232→ * Creates a behavior definition in the database.
233→ * Definitions start in "draft" status at version 1 with "warn_only" enforcement.
234→ */
235→export async function createBehaviorDefinition(
236→  surreal: Surreal,
237→  workspaceId: string,
238→  createdById: string,
239→  input: CreateBehaviorDefinitionInput,
240→): Promise<{ definitionId: string }> {
241→  const definitionId = `def-${crypto.randomUUID()}`;
242→  const definitionRecord = new RecordId("behavior_definition", definitionId);
243→  const workspaceRecord = new RecordId("workspace", workspaceId);
244→  const createdByRecord = new RecordId("identity", createdById);
245→
246→  const content: Record<string, unknown> = {
247→    title: input.title,
248→    goal: input.goal,
249→    scoring_logic: input.scoring_logic,
250→    telemetry_types: input.telemetry_types,
251→    status: "draft",
252→    version: 1,
253→    enforcement_mode: "warn_only",
254→    workspace: workspaceRecord,
255→    created_by: createdByRecord,
256→    created_at: new Date(),
257→  };
258→
259→  if (input.category !== undefined) content.category = input.category;
260→
261→  await surreal.query(`CREATE $definition CONTENT $content;`, {
262→    definition: definitionRecord,
263→    content,
264→  });
265→
266→  return { definitionId };
267→}
268→
269→/**
270→ * Retrieves a behavior definition by ID.
271→ * Returns undefined if not found.
272→ */
273→export async function getBehaviorDefinition(
274→  surreal: Surreal,
275→  definitionId: string,
276→): Promise<BehaviorDefinitionRecord | undefined> {
277→  const definitionRecord = new RecordId("behavior_definition", definitionId);
278→  const rows = (await surreal.query(
279→    `SELECT * FROM $definition;`,
280→    { definition: definitionRecord },
281→  )) as Array<BehaviorDefinitionRecord[]>;
282→  return rows[0]?.[0];
283→}
284→
285→/**
286→ * Lists behavior definitions for a workspace, optionally filtered by status.
287→ * Returns records ordered by created_at DESC.
288→ */
289→export async function listBehaviorDefinitions(
290→  surreal: Surreal,
291→  workspaceId: string,
292→  status?: DefinitionStatus,
293→): Promise<BehaviorDefinitionRecord[]> {
294→  const workspaceRecord = new RecordId("workspace", workspaceId);
295→
296→  const query = status
297→    ? `SELECT * FROM behavior_definition WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;`
298→    : `SELECT * FROM behavior_definition WHERE workspace = $ws ORDER BY created_at DESC;`;
299→  const rows = (await surreal.query(query, { ws: workspaceRecord, status })) as Array<BehaviorDefinitionRecord[]>;
300→  return rows[0] ?? [];
301→}
302→
303→/**
304→ * Updates a behavior definition.
305→ * - Validates status transitions (draft->active, active->archived, draft->archived only).
306→ * - Increments version when updating an active definition.
307→ * - Draft edits do not increment version.
308→ * Returns the updated record or throws on invalid transition.
309→ */
310→export async function updateBehaviorDefinition(
311→  surreal: Surreal,
312→  definitionId: string,
313→  input: UpdateBehaviorDefinitionInput,
314→): Promise<BehaviorDefinitionRecord> {
315→  const existing = await getBehaviorDefinition(surreal, definitionId);
316→  if (!existing) {
317→    throw new Error(`Behavior definition not found: ${definitionId}`);
318→  }
319→
320→  // Validate status transition if status is being changed
321→  if (input.status && input.status !== existing.status) {
322→    const error = validateStatusTransition(existing.status, input.status);
323→    if (error) throw new Error(error);
324→  }
325→
326→  const definitionRecord = new RecordId("behavior_definition", definitionId);
327→
328→  // Determine whether to increment version:
329→  // Only increment when the definition is active and content fields are being updated
330→  const isActive = existing.status === "active";
331→  const isContentUpdate = input.goal !== undefined
332→    || input.scoring_logic !== undefined
333→    || input.telemetry_types !== undefined
334→    || input.category !== undefined;
335→  const shouldIncrementVersion = isActive && isContentUpdate;
336→
337→  const setClauses: string[] = ["updated_at = time::now()"];
338→  const params: Record<string, unknown> = { def: definitionRecord };
339→
340→  if (input.goal !== undefined) {
341→    setClauses.push("goal = $goal");
342→    params.goal = input.goal;
343→  }
344→  if (input.scoring_logic !== undefined) {
345→    setClauses.push("scoring_logic = $scoring_logic");
346→    params.scoring_logic = input.scoring_logic;
347→  }
348→  if (input.telemetry_types !== undefined) {
349→    setClauses.push("telemetry_types = $telemetry_types");
350→    params.telemetry_types = input.telemetry_types;
351→  }
352→  if (input.category !== undefined) {
353→    setClauses.push("category = $category");
354→    params.category = input.category;
355→  }
356→  if (input.status !== undefined) {
357→    setClauses.push("status = $status");
358→    params.status = input.status;
359→  }
360→  if (input.enforcement_mode !== undefined) {
361→    setClauses.push("enforcement_mode = $enforcement_mode");
362→    params.enforcement_mode = input.enforcement_mode;
363→  }
364→  if (input.enforcement_threshold !== undefined) {
365→    setClauses.push("enforcement_threshold = $enforcement_threshold");
366→    params.enforcement_threshold = input.enforcement_threshold;
367→  }
368→  if (shouldIncrementVersion) {
369→    setClauses.push("version = version + 1");
370→  }
371→
372→  const query = `UPDATE $def SET ${setClauses.join(", ")};`;
373→  const rows = (await surreal.query(query, params)) as Array<BehaviorDefinitionRecord[]>;
374→  return rows[0][0];
375→}
