 4→  embeddingModel: Parameters<typeof embed>[0]["model"],
 5→  value: string,
 6→  expectedDimension: number,
 7→): Promise<number[] | undefined> {
 8→  const normalized = value.trim();
 9→  if (normalized.length === 0) {
10→    return undefined;
11→  }
12→
13→  const result = await embed({
14→    model: embeddingModel,
15→    value: normalized,
16→  });
17→
18→  if (result.embedding.length !== expectedDimension) {
19→    return undefined;
20→  }
21→
22→  return result.embedding;
23→}
24→
25→export function cosineSimilarity(a: number[], b: number[]): number {
26→  if (a.length !== b.length || a.length === 0) {
27→    return -1;
28→  }
29→
30→  let dot = 0;
31→  let normA = 0;
32→  let normB = 0;
33→
34→  for (let index = 0; index < a.length; index += 1) {
35→    dot += a[index] * b[index];
36→    normA += a[index] * a[index];
37→    normB += b[index] * b[index];
38→  }
39→
40→  if (normA === 0 || normB === 0) {
41→    return -1;
42→  }
43→
44→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
45→}
