 49→export type EvaluateIntentInput = {
 50→  intent: {
 51→    goal: string;
 52→    reasoning: string;
 53→    action_spec: ActionSpec;
 54→    budget_limit?: BudgetLimit;
 55→    priority?: number;
 56→  };
 57→  surreal: Surreal;
 58→  identityId: RecordId<"identity">;
 59→  workspaceId: RecordId<"workspace">;
 60→  requesterType: string;
 61→  requesterRole?: string;
 62→  llmEvaluator: LlmEvaluator;
 63→  timeoutMs?: number;
 64→  /** Optional: intent embedding for objective alignment (warning mode) */
 65→  intentEmbedding?: number[];
 66→  /** Optional: intent record ID for supports edge creation */
 67→  intentId?: RecordId<"intent">;
 68→  /** Optional: port to find aligned objectives via KNN */
 69→  findAlignedObjectives?: FindAlignedObjectives;
 70→  /** Optional: port to create supports edge */
 71→  createSupportsEdge?: CreateSupportsEdge;
 72→};
