 74→const DEFAULT_EVAL_TIMEOUT_MS = 30_000;
 75→
 76→export async function evaluateIntent(
 77→  input: EvaluateIntentInput,
 78→): Promise<EvaluationOutput> {
 79→  const intentContext: IntentEvaluationContext = {
 80→    goal: input.intent.goal,
 81→    reasoning: input.intent.reasoning,
 82→    priority: input.intent.priority ?? 0,
 83→    action_spec: input.intent.action_spec,
 84→    budget_limit: input.intent.budget_limit,
 85→    requester_type: input.requesterType,
 86→    requester_role: input.requesterRole,
 87→  };
 88→
 89→  const gateResult = await evaluatePolicyGate(
 90→    input.surreal,
 91→    input.identityId,
 92→    input.workspaceId,
 93→    intentContext,
 94→  );
 95→
 96→  if (!gateResult.passed) {
 97→    return {
 98→      decision: "REJECT",
 99→      risk_score: 0,
100→      reason: gateResult.reason,
101→      policy_only: true,
102→      policy_trace: gateResult.policy_trace,
103→      human_veto_required: false,
104→    };
105→  }
106→
107→  const humanVetoRequired = gateResult.human_veto_required;
108→  const policyTrace = gateResult.policy_trace;
109→
110→  // --- Alignment step (warning mode: never blocks authorization) ---
111→  let alignmentResult: AlignmentResult | undefined;
112→  if (input.intentEmbedding && input.findAlignedObjectives) {
113→    try {
114→      const candidates = await input.findAlignedObjectives(
115→        input.intentEmbedding,
116→        input.workspaceId,
117→      );
118→      alignmentResult = selectBestAlignment(candidates);
119→
120→      // Create supports edge if matched and ports are available
121→      if (
122→        alignmentResult.classification === "matched" &&
123→        alignmentResult.objectiveId &&
124→        input.intentId &&
125→        input.createSupportsEdge
126→      ) {
127→        await input.createSupportsEdge(
128→          input.intentId,
129→          alignmentResult.objectiveId,
130→          alignmentResult.score,
131→          "embedding",
132→        );
133→      }
134→    } catch {
135→      // Alignment failure never blocks intent authorization (warning mode)
136→      alignmentResult = { classification: "none", score: 0 };
137→    }
138→  }
139→
140→  const timeoutMs = input.timeoutMs ?? DEFAULT_EVAL_TIMEOUT_MS;
141→  const controller = new AbortController();
142→  const timer = setTimeout(() => controller.abort(), timeoutMs);
143→
144→  try {
145→    const llmResult = await input.llmEvaluator(input.intent, controller.signal);
146→    return {
147→      ...llmResult,
148→      policy_only: false,
149→      policy_trace: policyTrace,
150→      human_veto_required: humanVetoRequired,
151→      alignment: alignmentResult,
152→    };
153→  } catch (error) {
154→    const reason = isAbortError(error)
155→      ? "LLM evaluation timeout — falling back to policy-only with veto window"
156→      : `LLM evaluation failed: ${error instanceof Error ? error.message : String(error)} — falling back to policy-only with veto window`;
157→    return {
158→      decision: "APPROVE",
159→      risk_score: 50,
160→      reason,
161→      policy_only: true,
162→      policy_trace: policyTrace,
163→      human_veto_required: humanVetoRequired,
164→      alignment: alignmentResult,
165→    };
166→  } finally {
167→    clearTimeout(timer);
168→  }
169→}
170→
171→function isAbortError(error: unknown): boolean {
172→  return error instanceof DOMException && error.name === "AbortError";
173→}
