    content: {
      metric_type: opts.metric_type,
      score: opts.score,
      source_telemetry: opts.source_telemetry ?? {},
      workspace: workspaceRecord,
      created_at: opts.created_at ?? new Date(),
    },
  });

  // Create exhibits edge: identity ->exhibits-> behavior
