 * Gets the latest behavior score for an identity and metric type.
 */
export async function getLatestBehaviorScore(
  surreal: Surreal,
  identityId: string,
  metricType: string,
): Promise<number | undefined> {
  const records = await getBehaviorRecords(surreal, identityId, metricType);
